const settings = $('Load Global Settings').first()?.json ?? {};
const request = $('Add Refund Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? request.query ?? request ?? {};
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const parseNumber = (value) => {
  const normalized = clean(value).replace(/,/g, '');
  if (!normalized) return null;
  const parsed = Number.parseFloat(normalized);
  return Number.isFinite(parsed) ? parsed : null;
};
const parseDateInput = (value) => {
  const raw = clean(value);
  if (!raw) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  const match = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (!match) return raw;
  const [, day, month, year] = match;
  return `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
};
const parseBoolean = (value) => ['1', 'true', 'yes', 'on'].includes(clean(value).toLowerCase());
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
return [{ json: {
  name: clean(body.name),
  refund_for: clean(body.refund_for ?? body.for_name ?? body.for),
  reason: clean(body.reason),
  membership: clean(body.membership),
  amount: parseNumber(body.amount),
  from_date: parseDateInput(body.from_date ?? body.fromDate),
  to_date: parseDateInput(body.to_date ?? body.toDate),
  waive_admin_fee: parseBoolean(body.waive_admin_fee ?? body.waiveAdminFee),
  created_by: clean(body.created_by) || 'refund_form_webhook',
  return_url: clean(body.return_url) || `${n8nBaseUrl}/webhook/refunds`,
  n8n_base_url: n8nBaseUrl
} }];

const item = $input.first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sqlNumeric = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return String(Number(value));
};
const parseIsoDate = (value) => {
  const raw = clean(value);
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return null;
  const [, yearText, monthText, dayText] = match;
  const year = Number.parseInt(yearText, 10);
  const month = Number.parseInt(monthText, 10);
  const day = Number.parseInt(dayText, 10);
  if (!Number.isInteger(year) || !Number.isInteger(month) || !Number.isInteger(day)) return null;
  if (month < 1 || month > 12 || day < 1 || day > 31) return null;
  return { year, month, day, iso: `${yearText}-${monthText}-${dayText}` };
};
const formatMoney = (value) => {
  const rounded = Math.round((Number(value) + Number.EPSILON) * 100) / 100;
  const text = Number.isInteger(rounded) ? String(rounded) : rounded.toFixed(2).replace(/\.00$/, '').replace(/(\.\d)0$/, '$1');
  return `£${text}`;
};
const fail = (message) => [{ json: { ok: false, response_code: 400, message, return_url: item.return_url, n8n_base_url: item.n8n_base_url } }];
if (!clean(item.name)) return fail('Requestor name is required.');
if (!clean(item.refund_for)) return fail('Member name is required.');
if (!clean(item.reason)) return fail('Reason is required.');
if (!clean(item.membership)) return fail('Membership is required.');
if (item.amount === null || !Number.isFinite(Number(item.amount)) || Number(item.amount) < 0) return fail('Amount must be a valid number greater than or equal to zero.');
const fromDate = parseIsoDate(item.from_date);
const toDate = parseIsoDate(item.to_date);
if (!fromDate) return fail('From date must be a valid date.');
if (!toDate) return fail('To date must be a valid date.');
const fromMonthNumber = (fromDate.year * 12) + fromDate.month;
const toMonthNumber = (toDate.year * 12) + toDate.month;
const fromDayNumber = Date.UTC(fromDate.year, fromDate.month - 1, fromDate.day);
const toDayNumber = Date.UTC(toDate.year, toDate.month - 1, toDate.day);
if (toDayNumber < fromDayNumber) return fail('To date must be on or after from date.');
const months = (toMonthNumber - fromMonthNumber) + 1;
const waiveAdminFee = item.waive_admin_fee === true;
const adminFeeMonths = waiveAdminFee ? 0 : 1;
const refundableMonths = Math.max(months - adminFeeMonths, 0);
const refund = Math.round((Number(item.amount) * refundableMonths) / 12);
const explanation = waiveAdminFee
  ? `Refund of membership. Reason Player ${clean(item.reason)}. Repayment = ${formatMoney(item.amount)} * ${months}/12 months = ${formatMoney(refund)}. Admin fee waived.`
  : `Refund of membership. Reason Player ${clean(item.reason)}. Repayment = ${formatMoney(item.amount)} * (${months}-1)/12 months = ${formatMoney(refund)}. Includes 1 month admin fee.`;
return [{ json: {
  ok: true,
  return_url: item.return_url,
  n8n_base_url: item.n8n_base_url,
  waive_admin_fee: waiveAdminFee,
  sql: `with inserted as (\n  insert into public.refunds (\n    name,\n    refund_for,\n    reason,\n    membership,\n    amount,\n    from_date,\n    to_date,\n    months,\n    refund,\n    status,\n    explanation,\n    created_by\n  ) values (\n    ${sqlLiteral(item.name)},\n    ${sqlLiteral(item.refund_for)},\n    ${sqlLiteral(item.reason)},\n    ${sqlLiteral(item.membership)},\n    ${sqlNumeric(item.amount)},\n    ${sqlLiteral(fromDate.iso)}::date,\n    ${sqlLiteral(toDate.iso)}::date,\n    ${months},\n    ${sqlNumeric(refund)},\n    'New Request',\n    ${sqlLiteral(explanation)},\n    ${sqlLiteral(item.created_by)}\n  )\n  returning id, refund_for, membership, status\n)\nselect * from inserted;`
} }];

const input = $('Build Insert SQL').first()?.json ?? {};
const inserted = $('Insert Refund').first()?.json ?? {};
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const redirectTo = `${input.return_url || '#'}${(input.return_url || '').includes('?') ? '&' : '?'}message=${encodeURIComponent(inserted.id ? `Refund ${inserted.id} created for ${inserted.refund_for}` : 'Refund created')}${inserted.id ? `&id=${encodeURIComponent(inserted.id)}` : ''}`;
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=${escapeHtml(redirectTo)}"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Refund Created</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Refund Created</h1><p>Returning to refunds…</p><p><a class="button" href="${escapeHtml(redirectTo)}">Continue</a></p></div></body></html>`;
return [{ json: { html } }];

const input = $('Build Insert SQL').first()?.json ?? {};
const message = input.message || 'Refund could not be created.';
const redirectTo = `${input.return_url || '#'}${(input.return_url || '').includes('?') ? '&' : '?'}error=${encodeURIComponent(message)}`;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=${escapeHtml(redirectTo)}"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Refund Not Created</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Refund Not Created</h1><p>${escapeHtml(message)}</p><p><a class="button" href="${escapeHtml(redirectTo)}">Back to refunds</a></p></div></body></html>`;
return [{ json: { html } }];
